esqlQuery.esql:
FROM metrics-redisenterprise.otel-default
| WHERE listener_auth_errors IS NOT NULL
| STATS max_auth_errors = MAX(listener_auth_errors) BY bdb, endpoint, node, cluster
// Alert when authentication failures are detected at any listener endpoint
// Possible causes: credential rotation issues, misconfigured clients,
// or unauthorized access attempts
// Adjust threshold if your environment has expected auth retries
| WHERE max_auth_errors > 0
| SORT max_auth_errors DESC
